const body = $input.first().json.body;
const headers = $input.first().json.headers;
const secret = headers['x-webhook-secret'];

if (secret !== 'REDACTED_WEBHOOK_SECRET') {
  throw new Error('Unauthorized: Invalid webhook secret');
}

const toolCall = body.message.toolCallList[0];
const toolCallId = toolCall.id;
const args = toolCall.function.arguments;
const dateRange = args.date_range || 'naechste Woche';

const now = new Date();
const startTime = now.toISOString();
const endDate = new Date(now);
endDate.setDate(endDate.getDate() + 7);
const endTime = endDate.toISOString();

return [{ json: { toolCallId, dateRange, startTime, endTime } }];

const toolCallId = $('Extract Availability Request').first().json.toolCallId;
const slotsData = $input.first().json;

const dayNames = ['Sonntag','Montag','Dienstag','Mittwoch','Donnerstag','Freitag','Samstag'];
const monthNames = ['Januar','Februar','März','April','Mai','Juni','Juli','August','September','Oktober','November','Dezember'];

let allSlots = [];

// Handle Cal.com v2 response: { data: { "2026-03-02": [{start: "..."}] } }
const slotSource = slotsData.data || slotsData.slots || slotsData;

if (slotSource && typeof slotSource === 'object') {
  for (const dateKey of Object.keys(slotSource)) {
    const daySlots = slotSource[dateKey];
    if (Array.isArray(daySlots)) {
      for (const slot of daySlots) {
        const timeStr = slot.start || slot.time || slot;
        if (typeof timeStr === 'string') allSlots.push(timeStr);
      }
    }
  }
}

const maxSlots = allSlots.slice(0, 5);

if (maxSlots.length === 0) {
  return [{ json: { toolCallId, result: 'Leider sind in der gewünschten Zeitperiode keine Termine verfügbar. Soll ich einen anderen Zeitraum prüfen?' } }];
}

const formatted = maxSlots.map(timeStr => {
  const d = new Date(timeStr);
  const day = dayNames[d.getDay()];
  const date = d.getDate();
  const month = monthNames[d.getMonth()];
  // Show in Berlin time (UTC+1 in winter)
  const berlinOffset = 60; // CET = UTC+1
  const berlinDate = new Date(d.getTime() + berlinOffset * 60000);
  const hours = berlinDate.getUTCHours().toString().padStart(2,'0');
  const minutes = berlinDate.getUTCMinutes().toString().padStart(2,'0');
  return `${day}, ${date}. ${month} um ${hours}:${minutes} Uhr`;
}).join(', ');

const result = `Verfügbare Termine: ${formatted}`;

return [{ json: { toolCallId, result } }];

const body = $input.first().json.body;
const headers = $input.first().json.headers;
const secret = headers['x-webhook-secret'];

if (secret !== 'REDACTED_WEBHOOK_SECRET') {
  throw new Error('Unauthorized: Invalid webhook secret');
}

const toolCall = body.message.toolCallList[0];
const toolCallId = toolCall.id;
const args = toolCall.function.arguments;
const callId = body.message.call.id;

function sanitize(val, maxLen) {
  if (!val) return '';
  return String(val).replace(/[<>"';]/g, '').replace(/&/g, 'und').substring(0, maxLen || 200);
}

const datetime = sanitize(args.datetime, 200);
const name = sanitize(args.name, 200);
const email = sanitize(args.email, 200);
const company = sanitize(args.company, 200);

if (!datetime || !name || !email) {
  throw new Error('Missing required fields: datetime, name, email');
}

// Build Cal.com v1 booking payload as a JSON string
const calPayload = JSON.stringify({
  eventTypeId: 4897150,
  start: datetime,
  responses: { name, email },
  metadata: { company },
  timeZone: 'Europe/Berlin',
  language: 'de'
});

return [{ json: { toolCallId, callId, datetime, name, email, company, calPayload } }];

const response = $input.first().json;
const bookingData = $('Extract Booking Request').first().json;

const statusCode = response.statusCode || 200;

if (statusCode === 400 || statusCode === 409) {
  return [{ json: {
    toolCallId: bookingData.toolCallId,
    callId: bookingData.callId,
    datetime: bookingData.datetime,
    success: false,
    calBookingId: null,
    result: 'Dieser Zeitslot ist leider nicht mehr verfügbar. Soll ich andere Termine prüfen?'
  }}];
}

if (statusCode >= 400) {
  return [{ json: {
    toolCallId: bookingData.toolCallId,
    callId: bookingData.callId,
    datetime: bookingData.datetime,
    success: false,
    calBookingId: null,
    result: 'Die Terminbuchung ist leider fehlgeschlagen. Bitte versuchen Sie es erneut.'
  }}];
}

const booking = response.body || response;
const bookingId = (booking && (booking.uid || booking.id)) ? String(booking.uid || booking.id) : 'unknown';

return [{ json: {
  toolCallId: bookingData.toolCallId,
  callId: bookingData.callId,
  datetime: bookingData.datetime,
  success: true,
  calBookingId: bookingId,
  result: `Ihr Termin für die n8n Demo wurde erfolgreich gebucht für ${bookingData.datetime}. Sie erhalten eine Bestätigungsmail. Wir freuen uns auf das Gespräch!`
}}];

const body = $input.first().json.body;
const headers = $input.first().json.headers;
const secret = headers['x-webhook-secret'];

if (secret !== 'REDACTED_WEBHOOK_SECRET') {
  throw new Error('Unauthorized: Invalid webhook secret');
}

const toolCall = body.message.toolCallList[0];
const toolCallId = toolCall.id;
const args = toolCall.function.arguments;
const callId = body.message.call.id;

function sanitize(val, maxLen) {
  if (val === null || val === undefined) return null;
  const str = String(val);
  const cleaned = str
    .replace(/[<>"']/g, '')
    .replace(/;\s*(drop|delete|insert|update|select|union)/gi, '')
    .replace(/<script[^>]*>.*?<\/script>/gi, '')
    .substring(0, maxLen || 500);
  return cleaned.trim() || null;
}

const callIdClean = sanitize(callId, 255);
if (!callIdClean) throw new Error('Missing required field: call_id');

const caller_name = sanitize(args.caller_name, 500);
const company = sanitize(args.company, 500);
const company_size = sanitize(args.company_size, 500);
const current_stack = sanitize(args.current_stack, 500);
const pain_point = sanitize(args.pain_point, 500);
const timeline = sanitize(args.timeline, 500);
const email = sanitize(args.email, 500);
const phone = sanitize(args.phone, 50);

return [{ json: {
  toolCallId,
  call_id: callIdClean,
  caller_name,
  company,
  company_size,
  current_stack,
  pain_point,
  timeline,
  email,
  phone
} }];

